expressions.expression:
if PowerInvariant==0
    K1 = 0.5;
    K2 = 2/3;
else
    K1 = 1/sqrt(2);
    K2 = sqrt(2/3);
end

switch AxisAlignment
    case 'Q-axis'
        Offset = 0;
    case 'D-axis'
        Offset = pi/2;
    otherwise
end

if PowerInvariant==0
